import{_ as n,o as r,c as t,ag as i}from"./chunks/framework.DXGyWiRo.js";const s="/images/uebung082.jpg",a="/images/uebung081.jpg",m=JSON.parse('{"title":"Übung Lektion 50","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung50.md","filePath":"lektionen/uebung50.md"}'),u={name:"lektionen/uebung50.md"};function o(l,e,b,d,p,h){return r(),t("div",null,[...e[0]||(e[0]=[i('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-50" tabindex="-1">Übung Lektion 50 <a class="header-anchor" href="#ubung-lektion-50" aria-label="Permalink to &quot;Übung Lektion 50&quot;">​</a></h1><p>A) Zur Wiederholung der Deklination: folgender Vers enthält alle Deklinationsformen im Singular zu गुरु m.:</p><p>गुरुरेव गतिर्गुरुमेव भजे<br> गुरुणैव सहास्मि नमो गुरवे ।<br> न गुरोः परमं शिशुरस्मि गुरोर्<br> मतिरस्ति गुरौ मम पाहि गुरो ॥</p><blockquote><p>Mein Meister ist meine Zuflucht,<br> Meinen Meister liebe ich,<br> Ich bin mit meinem Meister zusammen,<br> Verehrung meinem Meister,<br> Es gibt nichts höheres als den Meister,<br> Ich bin das Kind meines Meisters,<br> Mein Herz ist bei meinem Meister,<br> Meister, hüte mich!</p></blockquote><p>B) Übersetzen Sie:</p><p>मनुस्मृति ४, १७८</p><p>येनास्य पितरो याता<br> येन याताः पितामहाः ।<br> तेन यायात्सतां मार्गम्<br> तेन गच्छन्न रिष्यते ॥१॥</p><blockquote><p>Man gehe auf dem Weg der Guten, auf dem die Väter gegangen sind, auf dem die Großväter gegangen sind, Wenn man auf diesem Weg geht, dann erleidet man keinen Schaden.</p></blockquote><p>मनुस्मृति ३, ६३</p><p>कुविवाहैः क्रियालोपैर्<br> वेदानध्ययनेन च ।<br> कुलान्यकुलतां यान्ति<br> ब्राह्मणातिक्रमेण च ॥२॥</p><blockquote><p>Familien werden zu Nichtfamilien durch schlechte Heiraten, durch Unterlassen der Riten, durch Nichtstudium der Veden und durch Vergehen gegen Brahmanen.</p></blockquote><p>मनुस्मृति ३, ६०</p><p>संतुष्टो भार्यया भर्ता<br> भर्त्रा भार्या तथैव च ।<br> यस्मिन्नेव कुले नित्यम्<br> कल्याणं तत्र वै ध्रुवम् ॥३॥</p><blockquote><p>Eine Familie, in der der Gatte mit der Gattin stets zufrieden ist und die Gattin mit dem Gatten, in einer solchen Familie ist stetes Glück gewiss.</p></blockquote><p>मनुस्मृति ३, ७५ - ७६: Über die Notwendigkeit des Opfers</p><p>स्वाध्याये नित्ययुक्तः स्याद्<br> दैवे चैवेह कर्मणि ।<br> दैवे कर्मणि युक्तो हि<br> बिभर्तीदं चराचरम् ॥४॥<br> अग्नौ प्रास्ताहुतिः सम्यग्<br> आदित्यमुपतिष्ठते ।<br> आदित्याज्जायते वृष्टिर्<br> वृष्टेरन्नं ततः प्रजाः ॥५॥</p><blockquote><p>Man engagiere sich stets im Vedastudium und in den Riten für die Götter. Wer sich in den Riten für die Götter engagiert, erhält nämlich diese Welt aus Belebtem und Unbelebtem. Das Opfer, das in rechter Weise ins Feuer geworfen wird, geht zur Sonne, aus der Sonne entsteht Regen, aus Regen Speise, daraus die Geschöpfe.</p></blockquote><p><img src="'+s+'" alt=""><br> Abb.: दैवे कर्मणि युक्तो हि<br> बिभर्तीदं चराचरम् ॥<br> ca. 1900<br> [Bildquelle: whatsthatpicture. -- <a href="http://www.flickr.com/photos/whatsthatpicture/2992703533/in/set-72157608574746511/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/whatsthatpicture/2992703533/in/set-72157608574746511/</a>. -- Zugriff am 2009-01-24. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung)]</p><p>योगसूत्र २, १६ - १७</p><p>हेयं दुःखमनागतम् ॥६॥<br> द्रष्टृदृश्ययोः संयोगो हेयहेतुः ॥७॥</p><blockquote><p>Aufzugeben ist das zukünftige Leiden.<br> Ursache dieses Aufzugebenden ist die Verbindung von Sehendem und Sichtbarem [= Wahrnehmendem und Wahrnehmbarem].</p></blockquote><p>कौटिलीयार्थशास्त्र १, १५: Über Ratgeber des Königs</p><p>न किंचिदवमन्येत<br> सर्वस्य शृणुयानमतम् ।<br> बालस्याप्यर्थवद्वाक्यम्<br> उपयुन्जीत पाण्डितः ॥८॥</p><blockquote><p>[Der König] soll nichts verschmähen, er höre die Meinung eines jeden. Ein Gelehrter eignet sich auch das Wort eine Knaben an, wenn es bedeutsam ist.</p></blockquote><p>मनुस्मृति २, १४० - १४२: Definition von आचार्य, उपाध्याय, गुरु</p><p>उपनीय तु यः शिष्यं<br> वेदमधापयेत्द्द्विजः ।<br> सकल्पं सरहस्यं च<br> तमाचार्यां प्रचक्षते ॥९॥</p><blockquote><p>Ācārya nennt man den Zweimalgeborenen, der dem Schüler Upanayana gibt und ihn dann den Veda, das Ritual und die Geheimlehre lehrt.</p></blockquote><p>एकदेशं तु वेदस्य<br> वेदाङ्गान्यपि वा पुनः ।<br> यो ऽध्यापयति वृत्त्यर्थम्<br> उपाध्यायः स उच्यते ॥१०॥</p><blockquote><p>Upādhyāya nennt man den, der um seines Lebensunterhalts willen einen Teil des Veda oder die Hilfswissenschaften lehrt.</p></blockquote><p>निषेकादीनि कर्माणि<br> यः करोति यथाविधि ।<br> संभावयति चान्नेन<br> स विप्रो गुरुरुच्यते ॥११॥</p><blockquote><p>Guru nennt man den Brahmanen, der vorschriftsgemäß Niṣeka und die anderen Rituale vollzieht und ihn durch Speise entstehen lässt.</p></blockquote><p>Zur Erklärung siehe:</p><p><img src="'+a+'" alt=""><br> Abb.:  संतुष्टो भार्यया भर्ता<br> भर्त्रा भार्या तथैव च ।<br> यस्मिन्नेव कुले नित्यम्<br> कल्याणं तत्र वै ध्रुवम् ॥<br> Christliche Familie, ca. 1900<br> [Bildquelle: whatsthatpicture. -- <a href="http://www.flickr.com/photos/whatsthatpicture/2993549480/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/whatsthatpicture/2993549480/</a>. -- Zugriff am 2009-01-24. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung)]</p>',34)])])}const g=n(u,[["render",o]]);export{m as __pageData,g as default};
